example.code:
-- In shared PostgreSQL (docker exec -it nero-postgres psql -U postgres)

-- Create per-project databases
CREATE DATABASE nero;
CREATE DATABASE meetingtax;
CREATE DATABASE eulaguard;

-- Create per-project users (isolated credentials)
CREATE USER nero_user WITH PASSWORD 'generate-with-openssl';
CREATE USER mtax_user WITH PASSWORD 'generate-with-openssl';
CREATE USER eulag_user WITH PASSWORD 'generate-with-openssl';

-- Grant access — each user can only access its own database
GRANT ALL PRIVILEGES ON DATABASE nero TO nero_user;
GRANT ALL PRIVILEGES ON DATABASE meetingtax TO mtax_user;
GRANT ALL PRIVILEGES ON DATABASE eulaguard TO eulag_user;

-- Set ownership so schema creation works
ALTER DATABASE nero OWNER TO nero_user;
ALTER DATABASE meetingtax OWNER TO mtax_user;
ALTER DATABASE eulaguard OWNER TO eulag_user;
